#include<bits/stdc++.h>
using namespace std;
double dis(double x1,double y1,double x2,double y2)
{
	return sqrt((x2-x1)*(x2-x1)+(y2-y1)*(y2-y1));
}
int main()
{
	double x[10],y[10];
	double s=0;
	for(int i=0;i<=2;i++)
	{
		scanf("%lf%lf",&x[i],&y[i]);
	}
	double a=dis(x[0],y[0],x[1],y[1]);
	double b=dis(x[0],y[0],x[2],y[2]);
	double c=dis(x[1],y[1],x[2],y[2]);
	s=s+a+b+c;
	printf("%.2lf",s);
	return 0;
}
